import { z } from 'zod';
import {
  trimAndRequire,
  phoneNumberSchema,
  numericString,
} from './helpers.js';

/**
 * Factory for the login form validation schema so translations can be injected.
 * Using a factory keeps validation logic centralized and reusable across UI layers.
 *
 * @param {import("react-i18next").TFunction} t - i18n translation function scoped to auth namespace.
 */
export const createLoginSchema = (t) =>
  z.object({
    email: z
      .string()
      .trim()
      .min(1, t('emailRequired', { ns: 'auth' }))
      .email(t('invalidEmail', { ns: 'auth' })),
    password: z
      .string()
      .min(1, t('passwordRequired', { ns: 'auth' })),
  });

/**
 * Helper to run safe validation and return a consistent error string.
 *
 * @param {import("react-i18next").TFunction} t
 * @param {{ email: string; password: string }} values
 * @returns {{ success: true } | { success: false; message: string }}
 */
export const validateLoginValues = (t, values) => {
  const schema = createLoginSchema(t);
  const result = schema.safeParse(values);

  if (result.success) {
    return { success: true };
  }

  const [issue] = result.error.issues;
  return {
    success: false,
    message: issue?.message ?? t('loginFailed', { ns: 'auth' }),
  };
};

const optionalNameField = (t, key, defaultMessage) =>
  z
    .string()
    .trim()
    .max(
      50,
      t(key, {
        ns: 'auth',
        defaultValue: defaultMessage,
      })
    )
    .optional()
    .or(z.literal(''));

const passwordField = (t) =>
  z
    .string()
    .min(8, t('passwordTooShort', { ns: 'auth' }))
    .superRefine((val, ctx) => {
      if (!/[A-Z]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainUppercase', { ns: 'auth' }),
        });
      }
      if (!/[a-z]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainLowercase', { ns: 'auth' }),
        });
      }
      if (!/[0-9]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainNumber', { ns: 'auth' }),
        });
      }
      // Allow all special characters (any character that is not alphanumeric or whitespace)
      if (!/[^a-zA-Z0-9\s]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainSpecial', { ns: 'auth' }),
        });
      }
    });

export const createRegisterSchema = (t) =>
  z
    .object({
      firstName: trimAndRequire(
        t('firstNameRequired', { ns: 'auth', defaultValue: 'First name is required' })
      ).max(
        50,
        t('firstNameTooLong', {
          ns: 'auth',
          defaultValue: 'First name cannot exceed 50 characters',
        })
      ),
      middleName: optionalNameField(
        t,
        'middleNameTooLong',
        'Middle name cannot exceed 50 characters'
      ),
      surname: trimAndRequire(
        t('surnameRequired', { ns: 'auth', defaultValue: 'Surname is required' })
      ).max(
        50,
        t('surnameTooLong', {
          ns: 'auth',
          defaultValue: 'Surname cannot exceed 50 characters',
        })
      ),
      email: z
        .string()
        .trim()
        .min(1, t('emailRequired', { ns: 'auth' }))
        .email(t('invalidEmail', { ns: 'auth' })),
      phoneCountryCode: trimAndRequire(
        t('phoneCountryCodeRequired', {
          ns: 'auth',
          defaultValue: 'Select a country code',
        })
      ),
      phone: phoneNumberSchema(
        t('invalidPhone', { ns: 'auth', defaultValue: 'Please enter a valid phone number' }),
        t('phoneNumberLength', {
          ns: 'auth',
          defaultValue: 'Phone number must be between 7 and 15 digits',
        })
      ),
      country: trimAndRequire(
        t('countryRequired', { ns: 'auth', defaultValue: 'Country is required' })
      ).max(
        100,
        t('countryTooLong', {
          ns: 'auth',
          defaultValue: 'Country cannot exceed 100 characters',
        })
      ),
      password: z
        .string()
        .pipe(passwordField(t)),
      confirmPassword: z
        .string()
        .min(
          1,
          t('confirmPasswordRequired', {
            ns: 'auth',
            defaultValue: 'Confirm password is required',
          })
        ),
    })
    .superRefine((data, ctx) => {
      if (data.password !== data.confirmPassword) {
        ctx.addIssue({
          path: ['confirmPassword'],
          code: z.ZodIssueCode.custom,
          message: t('passwordsDoNotMatch', { ns: 'auth' }),
        });
      }

      // Strict validation for Ghana numbers (+233)
      if (data.phoneCountryCode === '+233' && data.phone.length !== 9) {
        ctx.addIssue({
          path: ['phone'],
          code: z.ZodIssueCode.custom,
          message: t('ghanaPhoneLength', {
            ns: 'auth',
            defaultValue: 'Ghana phone numbers must be exactly 9 digits (excluding +233)'
          }),
        });
      }
    })
    .transform((data) => ({
      firstName: data.firstName.trim(),
      middleName: (data.middleName ?? '').trim(),
      surname: data.surname.trim(),
      email: data.email.trim().toLowerCase(),
      phoneCountryCode: data.phoneCountryCode.trim(),
      phone: data.phone.trim(),
      country: data.country.trim(),
      password: data.password,
      confirmPassword: data.confirmPassword,
    }));

export const createForgotPasswordSchema = (t) =>
  z.object({
    email: z
      .string()
      .trim()
      .min(1, t('emailRequired', { ns: 'auth' }))
      .email(t('invalidEmail', { ns: 'auth' })),
  });

export const createOtpSchema = (t) =>
  z.object({
    otp: numericString(t('pleaseEnterValidOTP', { ns: 'auth' })).refine(
      (val) => val.length === 6,
      {
        message: t('pleaseEnterValidOTP', { ns: 'auth' }),
      }
    ),
  });

