export const createBusinessRegistrationSchema = (t) =>
  z
    .object({
      businessType: trimAndRequire(
        t('businessTypeRequired', {
          ns: 'auth',
          defaultValue: 'Select a business type',
        })
      ),
      businessName: trimAndRequire(
        t('businessNameRequired', {
          ns: 'auth',
          defaultValue: 'Business name is required',
        })
      ).max(
        100,
        t('businessNameTooLong', {
          ns: 'auth',
          defaultValue: 'Business name cannot exceed 100 characters',
        })
      ),
      contactPerson: trimAndRequire(
        t('contactPersonRequired', {
          ns: 'auth',
          defaultValue: 'Contact person is required',
        })
      ).max(
        100,
        t('contactPersonTooLong', {
          ns: 'auth',
          defaultValue: 'Contact person cannot exceed 100 characters',
        })
      ),
      businessEmail: z
        .string()
        .trim()
        .min(1, t('businessEmailRequired', { ns: 'auth' }))
        .email(t('invalidEmail', { ns: 'auth' })),
      countryCode: trimAndRequire(
        t('countryCodeRequired', {
          ns: 'auth',
          defaultValue: 'Select a country code',
        })
      ),
      phoneNumber: phoneNumberSchema(
        t('invalidPhone', { ns: 'auth' }),
        t('phoneNumberLength', { ns: 'auth' })
      ),
      country: trimAndRequire(
        t('countryOfOperationRequired', {
          ns: 'auth',
          defaultValue: 'Country of operation is required',
        })
      ),
      category: trimAndRequire(
        t('businessCategoryRequired', {
          ns: 'auth',
          defaultValue: 'Business category is required',
        })
      ),
      innerCategory: z.string().optional().or(z.literal('')),
      password: passwordField(t),
      confirmPassword: z
        .string()
        .min(
          1,
          t('confirmPasswordRequired', {
            ns: 'auth',
            defaultValue: 'Confirm password is required',
          })
        ),
    })
    .superRefine((data, ctx) => {
      if (!['starter', 'registered', 'agent'].includes(data.businessType)) {
        ctx.addIssue({
          path: ['businessType'],
          code: z.ZodIssueCode.custom,
          message: t('businessTypeRequired', { ns: 'auth' }),
        });
      }

      if (data.password !== data.confirmPassword) {
        ctx.addIssue({
          path: ['confirmPassword'],
          code: z.ZodIssueCode.custom,
          message: t('passwordsDoNotMatch', { ns: 'auth' }),
        });
      }

      // Strict validation for Ghana numbers (+233)
      if (data.countryCode === '+233' && data.phoneNumber.length !== 9) {
        ctx.addIssue({
          path: ['phoneNumber'],
          code: z.ZodIssueCode.custom,
          message: t('ghanaPhoneLength', {
            ns: 'auth',
            defaultValue: 'Ghana phone numbers must be exactly 9 digits (excluding +233)'
          }),
        });
      }
    })
    .transform((data) => ({
      businessType: data.businessType.trim(),
      businessName: data.businessName.trim(),
      contactPerson: data.contactPerson.trim(),
      businessEmail: data.businessEmail.trim().toLowerCase(),
      countryCode: data.countryCode.trim(),
      phoneNumber: data.phoneNumber.trim(),
      country: data.country.trim(),
      category: data.category.trim(),
      innerCategory: data.innerCategory ? data.innerCategory.trim() : '',
      password: data.password,
      confirmPassword: data.confirmPassword,
    }));


